scwin.sbm_retrieve_submitdone = async function (e) {
  let rowCnt = ds_results.getRowCount();
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, "조회된 데이터가 없습니다.");
    return false;
  }
  if (acb_qryClsCd.getValue() == "Y") {
    // TODO: 배차 후 그리드 컬럼 readOnly 설정
    $c.gus.cfEnableObjects($p, [btn_transCopino, btn_delRow]);
    $c.gus.cfDisableObjects($p, [btn_cmbnR, btn_Open, btn_saveAndAutoEDI, btn_saveAndManualEDI]);
    ds_resultsVehcl.removeAll();
  } else {
    $c.gus.cfDisableObjects($p, [btn_transCopino, btn_delRow]);
    $c.gus.cfEnableObjects($p, [btn_cmbnR, btn_Open, btn_saveAndAutoEDI, btn_saveAndManualEDI]);
    let tempTime = "";
    for (let i = 0; i < rowCnt; i++) {
      if (ds_results.getCellData(i, "closeTime") != "") {
        tempTime = ds_results.getCellData(i, "closeTime");
        tempTime = tempTime.substr(0, 2) + "/" + tempTime.substr(2, 2) + " " + tempTime.substr(4, 2) + ":" + tempTime.substr(6, 2);
        ds_results.setCellData(i, "closeTime", tempTime);
      }
    }
  }
  if (acb_qryClsCd.getValue() == "N") {
    for (let j = 0; j < ds_results.getRowCount(); j++) {
      if (ds_results.getCellData(j, "openYn") == 1 && ds_results.getCellData(j, "chkMobile") == "Y") {
        let lobranCdVal = acb_lobranCd.getValue();
        let stDt = ica_dptIntendDd.getValue();
        let endDt = ica_dptIntendDd2.getValue();
        let odrNoVal = em_cntrOdrNo.getValue();
        let obj = {
          lobranCd: lobranCdVal,
          wrkDistrictCd1: "",
          clntNo: "",
          stDt: stDt,
          endDt: endDt,
          odrKndCd: "",
          noClsCd: "",
          odrNo: odrNoVal,
          railroadAdptDstCd: "",
          cargoClsCd: "C"
        };
        let rtnList = await $c.win.openPopup($p, "/ui/tn/op/rscmgnt/tn_305_01_09b.xml", {
          width: 500,
          height: 240,
          modal: true,
          data: obj
        });
        if (rtnList != null) {
          for (let ii = 0; ii < ds_results.getRowCount(); ii++) {
            if (ds_results.getCellData(ii, "odrNo") == rtnList[10] && ds_results.getCellData(ii, "openYn") == 1) {
              if (rtnList[0].trim() != "N/A") {
                ds_results.setCellData(ii, "vehclShortNo", rtnList[0]);
                ds_results.setCellData(ii, "vehclNo", rtnList[2]);
                ds_results.setCellData(ii, "eqCd", rtnList[8]);
                ds_results.setCellData(ii, "chk", 1);
              }
            }
          }
        }
        break;
      }
    }
  }
};
